"use client";

import React from "react";
import {
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";

import { cn } from "@/lib/utils";
import { DynamicRenderInput, HEIGHT_CLASSES } from "./render-dynamic-input";
import { CustomProps } from "./types";
import { FieldPath, FieldValues } from "react-hook-form";
import { FormFieldType } from "./constants";
import { FieldSkeletonLoader } from "./FieldSkeletonLoader";

function DynamicFormFieldInner<
  TFieldValues extends FieldValues,
  TName extends FieldPath<TFieldValues>
>(props: CustomProps<TFieldValues, TName>) {
  const {
    control,
    name,
    label,
    description,
    required,
    disabled,
    wrapperClassName,
    hideLabel,
    hideDescription,
    hideMessage,
    labelClassName,
    descriptionClassName,
    messageClassName,
    fieldType,
    height,
    renderSkeleton,
  } = props;

  /**
   * ⭐ SKELETON MODE
   * Use custom skeleton if provided, otherwise fallback to shimmer skeleton.
   * ✔ No styling altered
   * ✔ Height applied externally via HEIGHT_CLASSES
   */
  if (fieldType === FormFieldType.SKELETON) {
    return renderSkeleton ? (
      renderSkeleton({} as never)
    ) : (
      <FieldSkeletonLoader className={HEIGHT_CLASSES[height ?? "md"]} />
    );
  }

  /**
   * ⭐ Normal field rendering
   * Nothing removed. All props preserved.
   */
  return (
    <FormField
      control={control}
      name={name}
      disabled={disabled} // ✔ KEEP DISABLED SUPPORT
      render={({ field }) => (
        <FormItem className={cn("flex flex-col gap-1.5", wrapperClassName)}>
          {/* Label */}
          {!hideLabel && label && (
            <FormLabel
              className={cn("text-sm font-medium leading-none", labelClassName)}
            >
              {label}
              {required && <span className="text-destructive">*</span>}
            </FormLabel>
          )}

          {/* Description */}
          {!hideDescription && description && (
            <p
              className={cn(
                "text-xs leading-relaxed text-muted-foreground",
                descriptionClassName
              )}
            >
              {description}
            </p>
          )}

          {/* Input Renderer */}
          <DynamicRenderInput field={field} props={props} />

          {/* Validation Message */}
          {!hideMessage && (
            <FormMessage
              className={cn("text-xs font-medium", messageClassName)}
            />
          )}
        </FormItem>
      )}
    />
  );
}

export const DynamicFormField = React.memo(
  DynamicFormFieldInner
) as typeof DynamicFormFieldInner;

"use client";

import dynamic from "next/dynamic";
import React from "react";
import { FormControl } from "@/components/ui/form";
import { Checkbox } from "@/components/ui/checkbox";

import {
  InputGroup,
  InputGroupInput,
  InputGroupText,
  InputGroupTextarea,
} from "@/components/ui/input-group";

import { cn } from "@/lib/utils";
import {
  RenderInputProps,
  InputHeight,
  StringKeyOf,
  SelectLabelKey,
  toLazyFieldProps,
} from "./types";
import { FormFieldType } from "./constants";
import { FieldPath, FieldValues } from "react-hook-form";
import { applyMask } from "./field-utils/mask-utils";

/* -------------------------------------------------------------
 * LAZY COMPONENTS
 * ------------------------------------------------------------- */

const LazyDatePicker = dynamic(
  () => import("./inputs/date-picker").then((m) => m.DatePicker),
  { ssr: false }
);

const LazyPhoneInput = dynamic(
  () => import("./inputs/phone-input").then((m) => m.PhoneInput),
  { ssr: false }
);

const LazySelectInput = dynamic(
  () => import("./inputs/select-input").then((m) => m.SelectInput),
  { ssr: false }
);

const LazySingleSelector = dynamic(
  () => import("./inputs/single-selector").then((m) => m.SingleSelector),
  { ssr: false }
);

const LazyAsyncSelect = dynamic(
  () => import("./inputs/async-select").then((m) => m.AsyncSelect),
  { ssr: false }
);

const LazyPassword = dynamic(
  () => import("./inputs/input-password").then((m) => m.InputPassword),
  { ssr: false }
);

const LazzyCurrencyInput = dynamic(
  () => import("./inputs/currency-input").then((m) => m.CurrencyInput),
  { ssr: false }
);

const LazzyPercentInput = dynamic(
  () => import("./inputs/percent-input").then((m) => m.PercentInput),
  { ssr: false }
);

const LazySkeleton = dynamic(
  () => import("./FieldSkeletonLoader").then((m) => m.FieldSkeletonLoader),
  { ssr: false }
);

/* -------------------------------------------------------------
 * Schadcn native components
 * ------------------------------------------------------------- */

const LazySwitch = dynamic(
  () => import("@/components/ui/switch").then((m) => m.Switch),
  { ssr: false }
);

/* -------------------------------------------------------------
 * HEIGHT MAP (same as v3)
 * ------------------------------------------------------------- */

export const HEIGHT_CLASSES: Record<InputHeight, string> = {
  sm: "h-8",
  md: "h-9",
  lg: "h-10",
  xl: "h-11",
  auto: "h-auto",
};

const DEFAULT_HEIGHTS: Partial<Record<FormFieldType, InputHeight>> = {
  [FormFieldType.INPUT]: "md",
  [FormFieldType.PASSWORD]: "md",
  [FormFieldType.TEXTAREA]: "auto",
  [FormFieldType.DATE_PICKER]: "md",
  [FormFieldType.SELECT]: "md",
  [FormFieldType.SINGLE_SELECT]: "md",
  [FormFieldType.COMMAND]: "md",
  [FormFieldType.PHONE_INPUT]: "md",
  [FormFieldType.CHECKBOX]: "auto",
  [FormFieldType.HIDDEN]: "auto",
  [FormFieldType.SKELETON]: "auto",
  [FormFieldType.CURRENCY]: "md",
  [FormFieldType.PERCENT]: "md",
  [FormFieldType.MASKED]: "md",
  [FormFieldType.ASYNC_SELECT]: "md",
  [FormFieldType.SWITCH]: "auto",
};

/* -------------------------------------------------------------
 * MAIN COMPONENT
 * ------------------------------------------------------------- */

export const DynamicRenderInput = <
  TFieldValues extends FieldValues,
  TName extends FieldPath<TFieldValues>
>({
  field,
  props,
}: RenderInputProps<TFieldValues, TName>) => {
  const {
    fieldType,
    prefix,
    suffix,
    className,
    disabled,
    height,
    inputClassName,
  } = props;

  const heightClass =
    HEIGHT_CLASSES[height || DEFAULT_HEIGHTS[fieldType] || "md"];

  const groupClass = cn(
    "w-full flex items-center rounded-md border border-border bg-background",
    "transition-colors",
    "focus-within:border-primary/70",
    "focus-within:ring-1 focus-within:ring-primary/30",
    "hover:border-muted-foreground/40",
    disabled && "opacity-60 cursor-not-allowed",
    heightClass,
    className
  );

  const inputClasses = cn(
    "w-full bg-transparent text-sm leading-none",
    "placeholder:text-muted-foreground/60",
    "border-0 outline-none",
    "focus-visible:ring-0 focus-visible:ring-offset-0",
    inputClassName
  );

  /* -------------------------------------------------------------
   * SPECIAL NON-INPUTGROUP TYPES
   * ------------------------------------------------------------- */

  if (fieldType === FormFieldType.CHECKBOX) {
    return (
      <FormControl>
        <div className="flex items-center gap-2">
          <Checkbox
            id={field.name}
            checked={!!field.value}
            onCheckedChange={field.onChange}
            disabled={disabled}
          />
          {props.label && <label className="text-sm">{props.label}</label>}
        </div>
      </FormControl>
    );
  }

  if (fieldType === FormFieldType.HIDDEN) {
    return <input type="hidden" {...field} value={field.value ?? ""} />;
  }

  if (fieldType === FormFieldType.SKELETON) {
    return props.renderSkeleton ? (
      props.renderSkeleton(field)
    ) : (
      <LazySkeleton className={HEIGHT_CLASSES[props.height ?? "md"]} />
    );
  }

  /* -------------------------------------------------------------
   * BUILD controlChild (inside InputGroup)
   * ------------------------------------------------------------- */

  let controlChild: React.ReactNode = null;

  switch (fieldType) {
    /* ---------------- TEXTAREA ---------------- */
    case FormFieldType.TEXTAREA:
      controlChild = (
        <InputGroupTextarea
          {...props.textareaProps}
          {...field}
          disabled={disabled ?? props.textareaProps?.disabled}
          placeholder={
            props.placeholder ?? props.textareaProps?.placeholder ?? ""
          }
          className={cn(
            "resize-none py-1",
            inputClasses,
            props.textareaProps?.className
          )}
        />
      );
      break;

    /* ---------------- PASSWORD ---------------- */
    case FormFieldType.PASSWORD:
      controlChild = (
        <LazyPassword
          {...props.passwordProps}
          {...field}
          disabled={disabled ?? props.passwordProps?.disabled}
          placeholder={
            props.passwordProps?.placeholder ?? props.placeholder ?? ""
          }
          className={cn(inputClasses, props.passwordProps?.className)}
        />
      );
      break;

    case FormFieldType.SWITCH: {
      const heightClass =
        HEIGHT_CLASSES[height || DEFAULT_HEIGHTS[fieldType] || "md"];

      return (
        <FormControl>
          <div
            className={cn(
              "flex items-center",
              heightClass,
              disabled && "opacity-60"
            )}
          >
            <LazySwitch
              {...props.switchProps}
              checked={!!field.value}
              onCheckedChange={field.onChange}
              disabled={disabled}
            />
          </div>
        </FormControl>
      );
    }

    /* ---------------- DATE PICKER ---------------- */
    case FormFieldType.DATE_PICKER:
      controlChild = (
        <LazyDatePicker
          {...props}
          value={field.value}
          onChange={field.onChange}
          disabled={disabled}
          inputClassName={inputClasses}
        />
      );
      break;

    /* ---------------- PHONE INPUT ---------------- */
    case FormFieldType.PHONE_INPUT:
      controlChild = (
        <LazyPhoneInput
          {...field}
          placeholder={props.placeholder}
          disabled={disabled}
          className={cn(inputClasses, "text-right border-none h-full w-full")}
          defaultCountry="PH"
        />
      );
      break;

    /* ---------------- SELECT / SINGLE SELECT ---------------- */
    case FormFieldType.SELECT:
    case FormFieldType.SINGLE_SELECT:
      controlChild = (
        <LazySingleSelector
          field={field}
          data={props.data ?? []}
          label={props.label ?? ""}
          placeholder={props.placeholder}
          disabled={disabled}
          labelKey={props.labelKey ?? "label"}
          valueKey={props.valueKey ?? "value"}
          className={inputClasses}
        />
      );
      break;

    /* ---------------- COMMAND (SelectInput) ---------------- */
    case FormFieldType.COMMAND:
      controlChild = (
        <LazySelectInput
          field={field}
          data={props.data ?? []}
          label={props.label ?? ""}
          placeholder={props.placeholder}
          disabled={disabled}
          labelKey={props.labelKey ?? "label"}
          valueKey={props.valueKey ?? "value"}
          className={inputClasses}
        />
      );
      break;

    /* ---------------- ASYNC SELECT ---------------- */
    case FormFieldType.ASYNC_SELECT: {
      type Row = Record<string, unknown>;

      const asyncData = props.data ? ([...props.data] as Row[]) : undefined;

      const valueKey: StringKeyOf<Row> =
        (props.valueKey as StringKeyOf<Row>) ?? ("value" as StringKeyOf<Row>);

      const labelKey: SelectLabelKey<Row> =
        (props.selectLabelKey as SelectLabelKey<Row>) ?? "label";

      controlChild = (
        <LazyAsyncSelect
          value={field.value}
          onChange={field.onChange}
          data={asyncData}
          loadOptions={props.loadOptions}
          placeholder={props.placeholder}
          disabled={disabled}
          height={height || DEFAULT_HEIGHTS[fieldType] || "md"}
          valueKey={valueKey}
          selectLabelKey={labelKey}
          debounceTime={props.debounceTime ?? 300}
          onAddNew={props.onAddNew}
          addNewLabel={props.addNewLabel}
          // borderless={props.borderless}
          iconSearch={props.iconSearch ?? false}
        />
      );
      break;
    }

    /* ---------------- CURRENCY ---------------- */
    case FormFieldType.CURRENCY: {
      const lazy = toLazyFieldProps(field, props);

      controlChild = (
        <LazzyCurrencyInput
          {...lazy}
          disabled={disabled}
          className={cn(
            inputClasses,
            "text-right tabular-nums",
            props.className
          )}
        />
      );
      break;
    }

    /* ---------------- PERCENT ---------------- */

    case FormFieldType.PERCENT: {
      const lazy = toLazyFieldProps(field, props);

      controlChild = (
        <LazzyPercentInput
          {...lazy}
          disabled={disabled}
          className={cn(inputClasses, props.className)}
        />
      );
      break;
    }

    /* ---------------- MASKED ---------------- */
    case FormFieldType.MASKED:
      controlChild = (
        <InputGroupInput
          {...props.inputProps}
          {...field}
          disabled={disabled ?? props.inputProps?.disabled}
          placeholder={
            props.maskPlaceholder ??
            props.placeholder ??
            props.inputProps?.placeholder ??
            ""
          }
          className={cn(inputClasses, props.inputProps?.className)}
          value={applyMask(field.value ?? "", props.mask ?? "")}
          onChange={(e) =>
            field.onChange(applyMask(e.target.value, props.mask ?? ""))
          }
        />
      );
      break;

    /* ---------------- DEFAULT INPUT (FormFieldType.INPUT, fallback) ---------------- */
    default:
      controlChild = (
        <InputGroupInput
          {...props.inputProps}
          {...field} // 👈 This contains name, value, onChange, onBlur, and REF
          type={props.inputProps?.type ?? props.type ?? "text"}
          disabled={disabled ?? props.inputProps?.disabled}
          placeholder={props.placeholder ?? props.inputProps?.placeholder ?? ""}
          className={cn(inputClasses, props.inputProps?.className)}
          onChange={(e) => {
            // Special handling for number types
            if ((props.type ?? props.inputProps?.type) === "number") {
              const val = e.target.value === "" ? "" : Number(e.target.value);
              field.onChange(val);
            } else {
              // IMPORTANT: pass the full event for standard inputs
              field.onChange(e);
            }
          }}
          // Ensure we don't double-bind 'value' if it's already in ...field
        />
      );
  }

  /* -------------------------------------------------------------
   * FINAL RENDER WITH INPUTGROUP
   * ------------------------------------------------------------- */

  return (
    <InputGroup className={groupClass}>
      {prefix && (
        <InputGroupText className="px-2 text-xs text-muted-foreground/70 bg-muted/30">
          {prefix}
        </InputGroupText>
      )}

      <FormControl className="flex-1 h-full">{controlChild}</FormControl>

      {suffix && (
        <InputGroupText className="px-2 text-muted-foreground text-xs">
          {suffix}
        </InputGroupText>
      )}
    </InputGroup>
  );
};

"use client";

import { cn } from "@/lib/utils";
import { Skeleton } from "@/components/ui/skeleton";

/**
 * Base shimmer skeleton for form fields.
 * Height must be supplied externally via className="h-10"
 */
export function FieldSkeletonLoader({
  rounded = "rounded-md",
  className,
}: {
  rounded?: string;
  className?: string;
}) {
  return (
    <div
      className={cn(
        "relative w-full overflow-hidden",
        rounded,
        className
      )}
    >
      <Skeleton className="w-full h-full" />

      <div
        className={cn(
          "absolute inset-0 -translate-x-full",
          "animate-[shimmer_1.6s_infinite]",
          "bg-linear-to-r from-transparent via-white/40 to-transparent"
        )}
      />
    </div>
  );
}

import type {
  ControllerRenderProps,
  Control,
  FieldPath,
  FieldValues,
} from "react-hook-form";
import type { ComponentProps, ReactNode } from "react";
import type { FormFieldType } from "./constants";
import * as SwitchPrimitive from '@radix-ui/react-switch';

/* -------------------------------------------
 * HEIGHT TYPES
 * ------------------------------------------- */
export type InputHeight = "sm" | "md" | "lg" | "xl" | "auto";

/* -------------------------------------------
 * SELECT TYPES
 * ------------------------------------------- */

/** String-only keys of a row object */
export type StringKeyOf<T> = Extract<keyof T, string>;

/** Formatter function for select labels */
export type SelectFormatFn<Value = unknown, Row = unknown> = (
  value: Value,
  row: Row
) => string;

/**
 * Label configuration for select / async select
 */
export type SelectLabelKey<Row> =
  | StringKeyOf<Row>
  | {
      primary: {
        key: StringKeyOf<Row>;
        format?: SelectFormatFn<Row[StringKeyOf<Row>], Row>;
      };
      columns?: Array<{
        key: StringKeyOf<Row>;
        width?: number;
        format?: SelectFormatFn<Row[StringKeyOf<Row>], Row>;
      }>;
    };

/* -------------------------------------------
 * MAIN CUSTOM FIELD PROPS
 * ------------------------------------------- */

export interface CustomProps<
  TFieldValues extends FieldValues = FieldValues,
  TName extends FieldPath<TFieldValues> = FieldPath<TFieldValues>,
  TRow extends Record<string, unknown> = Record<string, unknown>
> {
  /* React Hook Form */
  control: Control<TFieldValues>;
  name: TName;
  fieldType: FormFieldType;

  /* Labels & text */
  label?: string;
  description?: string;
  placeholder?: string;

  /* State */
  disabled?: boolean;
  required?: boolean;

  /* Visibility */
  hideLabel?: boolean;
  hideDescription?: boolean;
  hideMessage?: boolean;

  /* Layout */
  height?: InputHeight;
  prefix?: ReactNode;
  suffix?: ReactNode;

  /* Styling */
  wrapperClassName?: string;
  className?: string;
  inputClassName?: string;
  labelClassName?: string;
  descriptionClassName?: string;
  messageClassName?: string;

  /* Native HTML passthrough */
  inputProps?: ComponentProps<"input">;
  textareaProps?: ComponentProps<"textarea">;
  passwordProps?: ComponentProps<"input">;
  switchProps?: ComponentProps<typeof SwitchPrimitive.Root>;

  /* ---------------- SELECT / COMMAND ---------------- */
  data?: TRow[];
  labelKey?: StringKeyOf<TRow>;
  valueKey?: StringKeyOf<TRow>;
  selectLabelKey?: SelectLabelKey<TRow>;

  /* ---------------- ASYNC SELECT ---------------- */
  loadOptions?: (query: string) => Promise<TRow[]>;
  debounceTime?: number;
  onAddNew?: () => void;
  addNewLabel?: string;
  borderless?: boolean;
  iconSearch?: boolean;

  /* ---------------- CURRENCY ---------------- */
  currencyLocale?: string;
  decimalPlaces?: number;
  thousandSeparator?: boolean;
  trimTrailingZeros?: boolean;

  /* ---------------- PERCENT ---------------- */
  percentDecimalPlaces?: number;
  textAlign?: "left" | "right";

  /* ---------------- MASKED INPUT ---------------- */
  mask?: string;
  maskPlaceholder?: string;

  /* ---------------- SKELETON ---------------- */
  renderSkeleton?: (
    field: ControllerRenderProps<TFieldValues, TName>
  ) => ReactNode;
  loaderMode?: "spinner" | "skeleton";
  loaderSize?: "sm" | "md" | "lg";
  loaderRadius?: "none" | "sm" | "md" | "lg";

  /* ---------------- DEFAULT INPUT ---------------- */
  type?: ComponentProps<"input">["type"];
}

/* -------------------------------------------
 * RENDER INPUT PROPS
 * ------------------------------------------- */

export interface RenderInputProps<
  TFieldValues extends FieldValues,
  TName extends FieldPath<TFieldValues>
> {
  field: ControllerRenderProps<TFieldValues, TName>;
  props: CustomProps<TFieldValues, TName>;
}

/* -------------------------------------------
 * Define a non-generic base props type for lazy inputs
 * ------------------------------------------- */

export interface LazyFieldInputProps {
  field: ControllerRenderProps<FieldValues, string>;
  props: CustomProps<FieldValues, string, Record<string, unknown>>;
  disabled?: boolean;
  className?: string;
}

/**
 * Widen RHF generics for lazy components.
 * This is a REQUIRED boundary for next/dynamic.
 */
export function toLazyFieldProps<
  TFieldValues extends FieldValues,
  TName extends FieldPath<TFieldValues>
>(
  field: ControllerRenderProps<TFieldValues, TName>,
  props: CustomProps<TFieldValues, TName>
) {
  return {
    field: field as unknown as ControllerRenderProps<FieldValues, string>,
    props: props as unknown as CustomProps<
      FieldValues,
      string,
      Record<string, unknown>
    >,
  };
}

export { DynamicFormField  } from "./DynamicFormField";
export * from "./constants";
export * from "./types";

export const applyMask = (value: string, mask: string): string => {
  const digits = value.replace(/\D/g, "");
  let result = "";
  let digitIndex = 0;

  for (let i = 0; i < mask.length; i++) {
    if (digitIndex >= digits.length) break;

    if (mask[i] === "#") {
      result += digits[digitIndex];
      digitIndex++;
    } else {
      result += mask[i];
    }
  }

  return result;
};

export const formatCurrency = (
  value: number,
  locale: string = "en-PH",
  decimals: number = 2,
  useThousands: boolean = true,
  trimZeros: boolean = false
): string => {
  if (isNaN(value)) return "";

  const options: Intl.NumberFormatOptions = {
    minimumFractionDigits: decimals,
    maximumFractionDigits: decimals,
    useGrouping: useThousands,
  };

  let formatted = new Intl.NumberFormat(locale, options).format(value);

  // Remove trailing zeros (optional)
  if (trimZeros) {
    formatted = formatted.replace(/\.?0+$/, "");
  }

  return formatted;
};


export const parseCurrency = (value: string): number | null => {
  if (!value) return null;
  const cleaned = value.replace(/[^0-9.-]+/g, "");
  const num = Number(cleaned);
  return isNaN(num) ? null : num;
};

"use client";

import { useEffect, useState, useRef, useCallback, KeyboardEvent } from "react";
import { cn } from "@/lib/utils";
import { Loader2, Plus, X, Search } from "lucide-react";
import { SelectLabelKey, StringKeyOf, InputHeight } from "../types";

export interface AsyncSelectProps<T extends Record<string, unknown>> {
  value: string | number | null;
  onChange: (value: string | number | null) => void;

  data?: T[];
  loadOptions?: (query: string) => Promise<T[]>;

  valueKey: StringKeyOf<T>;
  selectLabelKey: SelectLabelKey<T>;

  placeholder?: string;
  disabled?: boolean;
  debounceTime?: number;
  borderless?: boolean;
  height?: InputHeight;
  iconSearch?: boolean;

  onAddNew?: () => void;
  addNewLabel?: string;
}

/* ---------------------------------------------
 * Debounce hook helper
 * --------------------------------------------- */

function useDebounce<T>(value: T, delay: number = 300) {
  const [debounced, setDebounced] = useState(value);

  useEffect(() => {
    const timer = setTimeout(() => setDebounced(value), delay);
    return () => clearTimeout(timer);
  }, [value, delay]);

  return debounced;
}

/* ---------------------------------------------
 * Label extractors
 * --------------------------------------------- */

function getPrimary<T extends Record<string, unknown>>(
  item: T,
  key: SelectLabelKey<T>
): string {
  if (typeof key === "string") {
    return item[key] != null ? String(item[key]) : "";
  }

  const raw = item[key.primary.key];
  return key.primary.format
    ? String(key.primary.format(raw, item))
    : String(raw ?? "");
}

function getColumns<T extends Record<string, unknown>>(
  item: T,
  key: SelectLabelKey<T>
) {
  if (typeof key === "string" || !key.columns) return [];

  return key.columns.map((c) => {
    const raw = item[c.key];
    const formatted = c.format ? c.format(raw, item) : raw;

    return {
      width: c.width ?? 140,
      value: formatted != null ? String(formatted) : "",
    };
  });
}

/* ---------------------------------------------
 * HEIGHT CLASSES (should match render-dynamic-input.tsx)
 * --------------------------------------------- */
const HEIGHT_CLASSES: Record<InputHeight, string> = {
  sm: "h-8",
  md: "h-9",
  lg: "h-10",
  xl: "h-11",
  auto: "h-auto",
};

/* ---------------------------------------------
 * PADDING CLASSES based on height for consistency
 * --------------------------------------------- */
const PADDING_CLASSES: Record<InputHeight, { x: string; iconLeft: string; iconRight: string }> = {
  sm: { x: "px-2", iconLeft: "left-2", iconRight: "right-2" },
  md: { x: "px-3", iconLeft: "left-3", iconRight: "right-3" },
  lg: { x: "px-3", iconLeft: "left-3", iconRight: "right-3" },
  xl: { x: "px-4", iconLeft: "left-4", iconRight: "right-4" },
  auto: { x: "px-3", iconLeft: "left-3", iconRight: "right-3" },
};

/* ---------------------------------------------
 * MAIN COMPONENT
 * --------------------------------------------- */
export function AsyncSelect<T extends Record<string, unknown>>({
  value,
  onChange,
  data,
  loadOptions,
  valueKey,
  selectLabelKey,
  placeholder = "Select...",
  disabled = false,
  debounceTime = 300,
  // borderless = false,
  height = "md",
  iconSearch = false,
  onAddNew,
  addNewLabel = "Add New",
}: AsyncSelectProps<T>) {
  const containerRef = useRef<HTMLDivElement>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const [query, setQuery] = useState("");
  const [options, setOptions] = useState<T[]>([]);
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [highlightIndex, setHighlightIndex] = useState(-1);
  const [position, setPosition] = useState<"above" | "below">("below");

  const debouncedQuery = useDebounce(query, debounceTime);
  const hasStatic = Array.isArray(data) && data.length > 0;

  const padding = PADDING_CLASSES[height];

  /* ---------------------------------------------
   * Fetch list
   * --------------------------------------------- */
  const fetchList = useCallback(
    async (search: string): Promise<T[]> => {
      const q = search.toLowerCase();

      if (hasStatic && data) {
        return data.filter((item) =>
          getPrimary(item, selectLabelKey).toLowerCase().includes(q)
        );
      }

      return loadOptions ? loadOptions(search) : [];
    },
    [hasStatic, data, loadOptions, selectLabelKey]
  );

  /* ---------------------------------------------
   * Hydrate selected value
   * --------------------------------------------- */
  useEffect(() => {
    if (value == null) return;

    const loadSource =
      hasStatic && data
        ? Promise.resolve(data)
        : loadOptions?.("") ?? Promise.resolve([]);

    loadSource.then((source) => {
      const found = source.find((item) => item[valueKey] === value);
      if (found) setQuery(getPrimary(found, selectLabelKey));
    });
  }, [value, data, loadOptions, hasStatic, selectLabelKey, valueKey]);

  /* ---------------------------------------------
   * Search effect
   * --------------------------------------------- */
  useEffect(() => {
    let cancelled = false;

    const run = async () => {
      setLoading(true);

      const list =
        debouncedQuery.trim() === ""
          ? await fetchList("")
          : await fetchList(debouncedQuery);

      if (cancelled) return;

      setOptions(list);
      setHighlightIndex(list.length > 0 ? 0 : -1);
      setLoading(false);
    };

    run();

    return () => {
      cancelled = true;
    };
  }, [debouncedQuery, fetchList]);

  const openList = () => {
    setLoading(true);
    fetchList("")
      .then((list) => {
        setOptions(list);
        setHighlightIndex(list.length > 0 ? 0 : -1);
      })
      .finally(() => setLoading(false));

    setOpen(true);
    // Focus the input when dropdown opens
    setTimeout(() => {
      inputRef.current?.focus();
    }, 0);
  };

  /* ---------------------------------------------
   * Dropdown placement
   * --------------------------------------------- */
  const computePlacement = useCallback(() => {
    if (!containerRef.current || !dropdownRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const dropdownHeight = dropdownRef.current.offsetHeight;

    const spaceBelow = window.innerHeight - rect.bottom;
    const spaceAbove = rect.top;

    setPosition(
      spaceBelow < dropdownHeight && spaceAbove > dropdownHeight
        ? "above"
        : "below"
    );
  }, []);

  useEffect(() => {
    if (open) requestAnimationFrame(computePlacement);
  }, [open, options, computePlacement]);

  /* ---------------------------------------------
   * Outside click to close
   * --------------------------------------------- */
  useEffect(() => {
    const handler = (event: MouseEvent) => {
      if (
        containerRef.current &&
        !containerRef.current.contains(event.target as Node)
      ) {
        setOpen(false);
      }
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  /* ---------------------------------------------
   * Keyboard navigation
   * --------------------------------------------- */
  const onKeyDown = (e: KeyboardEvent<HTMLInputElement>) => {
    if (!open) return;

    if (e.key === "ArrowDown") {
      e.preventDefault();
      setHighlightIndex((i) => Math.min(i + 1, options.length));
    }

    if (e.key === "ArrowUp") {
      e.preventDefault();
      setHighlightIndex((i) => Math.max(i - 1, 0));
    }

    if (e.key === "Enter") {
      e.preventDefault();

      if (highlightIndex === options.length && onAddNew) {
        onAddNew();
        setOpen(false);
        return;
      }

      if (highlightIndex >= 0 && highlightIndex < options.length) {
        const item = options[highlightIndex];
        onChange(item[valueKey] as never);
        setQuery(getPrimary(item, selectLabelKey));
        setOpen(false);
      }
    }

    if (e.key === "Escape") setOpen(false);
  };

  /* ---------------------------------------------
   * Handle clear button
   * --------------------------------------------- */
  const handleClear = () => {
    setQuery("");
    onChange(null);
    setOpen(false);
    inputRef.current?.focus();
  };

  /* ---------------------------------------------
   * Wrapper and input styling
   * --------------------------------------------- */
  const wrapperClass = cn(
    "relative w-full h-full flex items-center",
    HEIGHT_CLASSES[height],
    disabled && "opacity-50 cursor-not-allowed"
  );

  // Calculate left padding based on iconSearch
  const getLeftPadding = () => {
    return iconSearch ? `pl-10` : padding.x.split(" ")[0];
  };

  // Calculate right padding based on clear/loading buttons
  const getRightPadding = () => {
    if (query || loading) {
      return "pr-10";
    }
    return padding.x.split(" ")[1] || "pr-3";
  };

  const inputClass = cn(
    "w-full h-full bg-transparent text-sm leading-none",
    "placeholder:text-muted-foreground/60",
    "focus-visible:outline-none focus-visible:ring-0",
    "border-0 outline-none",
    disabled && "cursor-not-allowed",
    getLeftPadding(),
    getRightPadding()
  );

  /* ---------------------------------------------
   * RENDER
   * --------------------------------------------- */
  return (
    <div ref={containerRef} className="relative w-full h-full">
      <div className={wrapperClass}>
        {/* Search Icon - More subtle styling */}
        {iconSearch && (
          <div className={cn(
            "absolute top-1/2 -translate-y-1/2",
            padding.iconLeft,
            "text-muted-foreground/70"
          )}>
            <Search className="h-4 w-4" />
          </div>
        )}

        {/* Input */}
        <input
          ref={inputRef}
          type="text"
          disabled={disabled}
          placeholder={placeholder}
          value={query}
          onFocus={openList}
          onChange={(e) => {
            setQuery(e.target.value);
            setOpen(true);
          }}
          onKeyDown={onKeyDown}
          className={inputClass}
        />

        {/* Loading Spinner */}
        {loading && (
          <div className={cn(
            "absolute top-1/2 -translate-y-1/2",
            padding.iconRight,
            "text-muted-foreground"
          )}>
            <Loader2 className="h-4 w-4 animate-spin" />
          </div>
        )}

        {/* Clear Button */}
        {query && !loading && (
          <button
            type="button"
            onClick={handleClear}
            className={cn(
              "absolute top-1/2 -translate-y-1/2",
              padding.iconRight,
              "text-muted-foreground hover:text-foreground transition-colors"
            )}
          >
            <X className="h-4 w-4" />
          </button>
        )}
      </div>

      {/* Dropdown */}
      {open && (
        <div
          ref={dropdownRef}
          className={cn(
            "absolute left-0 right-0 z-50",
            "rounded-md border border-border bg-popover",
            "shadow-md animate-in fade-in zoom-in-95",
            position === "below" ? "top-full mt-1" : "bottom-full mb-1"
          )}
        >
          <div className="max-h-64 overflow-auto py-1">
            {loading && (
              <div className="px-3 py-2 text-sm text-muted-foreground">
                Loading...
              </div>
            )}

            {!loading && options.length === 0 && (
              <div className="px-3 py-3 text-center text-sm text-muted-foreground/80">
                No results found.
              </div>
            )}

            {!loading &&
              options.map((item, idx) => {
                const primary = getPrimary(item, selectLabelKey);
                const cols = getColumns(item, selectLabelKey);

                return (
                  <button
                    key={String(item[valueKey])}
                    type="button"
                    onMouseEnter={() => setHighlightIndex(idx)}
                    onClick={() => {
                      onChange(item[valueKey] as never);
                      setQuery(primary);
                      setOpen(false);
                    }}
                    className={cn(
                      "w-full text-left px-3 py-2 hover:bg-accent hover:text-accent-foreground",
                      "transition-colors duration-150",
                      highlightIndex === idx &&
                        "bg-accent text-accent-foreground",
                      "flex items-center justify-between"
                    )}
                  >
                    <div className="flex-1 truncate text-sm">
                      {primary}
                    </div>

                    {cols.length > 0 && (
                      <div className="flex items-center space-x-4 ml-4 text-xs text-muted-foreground">
                        {cols.map((c, i) => (
                          <div
                            key={i}
                            style={{ width: c.width }}
                            className="truncate"
                          >
                            {c.value}
                          </div>
                        ))}
                      </div>
                    )}
                  </button>
                );
              })}
          </div>

          {/* Add New Button */}
          {onAddNew && (
            <div className="sticky bottom-0 border-t border-border bg-popover">
              <button
                type="button"
                onClick={() => {
                  onAddNew();
                  setOpen(false);
                }}
                className={cn(
                  "flex w-full items-center gap-2 px-3 py-2 text-sm text-primary",
                  "hover:bg-accent hover:text-accent-foreground transition-colors",
                  highlightIndex === options.length &&
                    "bg-accent text-accent-foreground"
                )}
              >
                <Plus className="h-4 w-4" /> {addNewLabel}
              </button>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

"use client";

import * as React from "react";
import { CheckIcon, ChevronsUpDown } from "lucide-react";
import * as RPNInput from "react-phone-number-input";
import flags from "react-phone-number-input/flags";

import { Button } from "@/components/ui/button";
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from "@/components/ui/command";
import { Input } from "@/components/ui/input";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { ScrollArea } from "@/components/ui/scroll-area";
import { cn } from "@/lib/utils";

/* -------------------------------------------------------------
 * TYPES
 * ------------------------------------------------------------- */

type PhoneInputProps = Omit<
  React.ComponentProps<"input">,
  "onChange" | "value" | "ref"
> &
  Omit<RPNInput.Props<typeof RPNInput.default>, "onChange"> & {
    onChange?: (value: RPNInput.Value) => void;
  };

/* -------------------------------------------------------------
 * MAIN PHONE INPUT
 * ------------------------------------------------------------- */

export const PhoneInput = React.forwardRef<
  React.ComponentRef<typeof RPNInput.default>,
  PhoneInputProps
>(({ className, onChange, value, ...props }, ref) => {
  return (
    <RPNInput.default
      ref={ref}
      className={cn(
        "flex w-full items-stretch rounded-md border border-border bg-input",
        "focus-within:ring-2 focus-within:ring-primary/40 focus-within:border-primary",
        className
      )}
      flagComponent={FlagComponent}
      countrySelectComponent={CountrySelect}
      inputComponent={InputComponent}
      smartCaret={false}
      value={value || undefined}
      onChange={(v) => onChange?.(v || ("" as RPNInput.Value))}
      {...props}
    />
  );
});
PhoneInput.displayName = "PhoneInput";

/* -------------------------------------------------------------
 * INPUT PART
 * ------------------------------------------------------------- */

const InputComponent = React.forwardRef<
  HTMLInputElement,
  React.ComponentProps<"input">
>(({ className, ...props }, ref) => (
  <Input
    ref={ref}
    className={cn(
      "flex-1 h-full border-0 rounded-none bg-transparent px-3 text-sm",
      "focus-visible:ring-0 focus-visible:ring-offset-0",
      className
    )}
    {...props}
  />
));
InputComponent.displayName = "InputComponent";

/* -------------------------------------------------------------
 * COUNTRY SELECT
 * ------------------------------------------------------------- */

type CountryEntry = {
  label: string;
  value: RPNInput.Country | undefined;
};

type CountrySelectProps = {
  disabled?: boolean;
  value: RPNInput.Country;
  options: CountryEntry[];
  onChange: (country: RPNInput.Country) => void;
};

const CountrySelect = ({
  disabled,
  value: selectedCountry,
  options: countryList,
  onChange,
}: CountrySelectProps) => {
  const scrollAreaRef = React.useRef<HTMLDivElement>(null);
  const [searchValue, setSearchValue] = React.useState("");
  const [isOpen, setIsOpen] = React.useState(false);

  /* ✅ Reset scroll when search changes */
  React.useEffect(() => {
    const viewport = scrollAreaRef.current?.querySelector(
      "[data-radix-scroll-area-viewport]"
    ) as HTMLElement | null;

    if (viewport) viewport.scrollTop = 0;
  }, [searchValue]);

  /* ✅ MANUAL FILTERING (FIXES SEARCH) */
  const filteredCountries = React.useMemo(() => {
    if (!searchValue.trim()) return countryList;

    const q = searchValue.toLowerCase();

    return countryList.filter(
      (c) => c.value && c.label.toLowerCase().includes(q)
    );
  }, [countryList, searchValue]);

  /* ✅ Memoized rendering */
  const renderedOptions = React.useMemo(
    () =>
      filteredCountries.map(({ value, label }) =>
        value ? (
          <CountrySelectOption
            key={value}
            country={value}
            countryName={label}
            selectedCountry={selectedCountry}
            onChange={onChange}
            onSelectComplete={() => setIsOpen(false)}
          />
        ) : null
      ),
    [filteredCountries, selectedCountry, onChange]
  );

  return (
    <Popover
      open={isOpen}
      onOpenChange={(open) => {
        setIsOpen(open);
        if (open) setSearchValue("");
      }}
    >
      <PopoverTrigger asChild>
        <Button
          type="button"
          variant="ghost"
          className={cn(
            "flex h-full items-center gap-1 rounded-none rounded-l-md",
            "border-0 border-r border-border bg-transparent px-2",
            "focus-visible:ring-0 focus-visible:ring-offset-0",
            disabled && "opacity-50 cursor-not-allowed"
          )}
          disabled={disabled}
        >
          <FlagComponent
            country={selectedCountry}
            countryName={selectedCountry}
          />
          <ChevronsUpDown
            className={cn(
              "size-4 opacity-60",
              disabled && "opacity-0 pointer-events-none"
            )}
          />
        </Button>
      </PopoverTrigger>

      <PopoverContent className="w-72 p-0">
        <Command shouldFilter={false}>
          <CommandInput
            value={searchValue}
            onValueChange={setSearchValue}
            placeholder="Search country..."
          />

          <CommandList>
            <ScrollArea ref={scrollAreaRef} className="h-72">
              {filteredCountries.length === 0 && (
                <CommandEmpty>No country found.</CommandEmpty>
              )}

              <CommandGroup>{renderedOptions}</CommandGroup>
            </ScrollArea>
          </CommandList>
        </Command>
      </PopoverContent>
    </Popover>
  );
};

/* -------------------------------------------------------------
 * COUNTRY OPTION
 * ------------------------------------------------------------- */

interface CountrySelectOptionProps extends RPNInput.FlagProps {
  selectedCountry: RPNInput.Country;
  onChange: (country: RPNInput.Country) => void;
  onSelectComplete: () => void;
}

const CountrySelectOption = React.memo(
  ({
    country,
    countryName,
    selectedCountry,
    onChange,
    onSelectComplete,
  }: CountrySelectOptionProps) => {
    const handleSelect = () => {
      onChange(country);
      onSelectComplete();
    };

    return (
      <CommandItem className="gap-2" onSelect={handleSelect}>
        <FlagComponent country={country} countryName={countryName} />
        <span className="flex-1 text-sm">{countryName}</span>
        <span className="text-sm text-foreground/50">
          +{RPNInput.getCountryCallingCode(country)}
        </span>
        <CheckIcon
          className={cn(
            "ml-auto size-4",
            country === selectedCountry ? "opacity-100" : "opacity-0"
          )}
        />
      </CommandItem>
    );
  }
);
CountrySelectOption.displayName = "CountrySelectOption";

/* -------------------------------------------------------------
 * FLAG (MEMOIZED)
 * ------------------------------------------------------------- */

const FlagComponent = React.memo(
  ({ country, countryName }: RPNInput.FlagProps) => {
    const Flag = flags[country];

    return (
      <span className="flex h-4 w-6 overflow-hidden rounded-sm bg-foreground/20 [&_svg:not([class*='size-'])]:size-full">
        {Flag && <Flag title={countryName} />}
      </span>
    );
  }
);
FlagComponent.displayName = "FlagComponent";

import { ControllerRenderProps, FieldPath, FieldValues } from "react-hook-form";

import React, { useState } from "react";

import { cn } from "@/lib/utils";
import { RenderInputProps } from "../types";
import { Input } from "@/components/ui/input";

export function PercentInput<
  TFieldValues extends FieldValues,
  TName extends FieldPath<TFieldValues>
>({
  field,
  props,
  disabled,
  className,
}: {
  field: ControllerRenderProps<TFieldValues, TName>;
  props: RenderInputProps<TFieldValues, TName>["props"];
  disabled?: boolean;
  className?: string;
}) {
  const [uiValue, setUiValue] = useState("");

  React.useEffect(() => {
    if (typeof field.value === "number") {
      setUiValue(
        (field.value * 100).toFixed(props.percentDecimalPlaces ?? 2) + "%"
      );
    } else {
      setUiValue("");
    }
  }, [field.value, props.percentDecimalPlaces]);

  return (
    <Input
      {...props.inputProps}
      {...field}
      disabled={disabled ?? props.inputProps?.disabled}
      className={cn("text-right tabular-nums", className)}
      value={uiValue}
      placeholder={props.placeholder ?? props.inputProps?.placeholder ?? "0%"}
      onChange={(e) => {
        if (/^[0-9.%]*$/.test(e.target.value)) setUiValue(e.target.value);
      }}
      onBlur={() => {
        const raw = uiValue.replace("%", "").trim();
        const parsed = parseFloat(raw);
        if (isNaN(parsed)) {
          field.onChange(null);
          setUiValue("");
        } else {
          field.onChange(parsed / 100);
          setUiValue(parsed.toFixed(props.percentDecimalPlaces ?? 2) + "%");
        }
      }}
    />
  );
}

import React from "react";

import { cn } from "@/lib/utils";
import { LazyFieldInputProps } from "../types";
import { formatCurrency } from "../field-utils/currency-utils";
import { Input } from "@/components/ui/input";

export function CurrencyInput({
  field,
  props,
  disabled,
  className,
}: LazyFieldInputProps) {
  const [uiValue, setUiValue] = React.useState("");

  React.useEffect(() => {
    if (typeof field.value === "number") {
      setUiValue(
        formatCurrency(
          field.value,
          props.currencyLocale ?? "en-PH",
          props.decimalPlaces ?? 2,
          props.thousandSeparator ?? true,
          props.trimTrailingZeros ?? false
        )
      );
    } else {
      setUiValue("");
    }
  }, [
    field.value,
    props.currencyLocale,
    props.decimalPlaces,
    props.thousandSeparator,
    props.trimTrailingZeros,
  ]);

  return (
    <Input
      {...props.inputProps}
      {...field}
      disabled={disabled ?? props.inputProps?.disabled}
      className={cn("text-right tabular-nums", className)}
      value={uiValue}
      placeholder={props.placeholder ?? props.inputProps?.placeholder ?? ""}
      onChange={(e) => {
        const raw = e.target.value;
        if (/^[0-9,.\s]*$/.test(raw)) setUiValue(raw);
      }}
      onBlur={() => {
        const num = parseFloat(uiValue.replace(/,/g, ""));
        if (isNaN(num)) {
          field.onChange(null);
          setUiValue("");
        } else {
          field.onChange(num);
          setUiValue(
            formatCurrency(
              num,
              props.currencyLocale ?? "en-PH",
              props.decimalPlaces ?? 2,
              props.thousandSeparator ?? true,
              props.trimTrailingZeros ?? false
            )
          );
        }
      }}
    />
  );
}

"use client";

import * as React from "react";
import { CalendarDays } from "lucide-react";
import { format } from "date-fns";

import { Button } from "@/components/ui/button";
import { Calendar } from "@/components/ui/calendar";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { Input } from "@/components/ui/input";
import { cn } from "@/lib/utils";

interface DatePickerProps {
  value?: Date | string;
  onChange?: (date: Date | undefined) => void;
  placeholder?: string;
  className?: string;
  inputClassName?: string; // NEW: Specific input styling
  disabled?: boolean;
}

export function DatePicker({
  value,
  onChange,
  placeholder = "Select date",
  className,
  inputClassName, // NEW: Accept input-specific classes
  disabled = false,
}: DatePickerProps) {
  const [open, setOpen] = React.useState(false);
  const [inputValue, setInputValue] = React.useState(
    value
      ? typeof value === "string"
        ? value
        : format(value, "MM/dd/yyyy")
      : ""
  );

  // ✅ Single parser: MMDDYYYY or MM/DD/YYYY
  function parseDate(input: string): Date | undefined {
    const digits = input.replace(/\D/g, "");
    if (digits.length === 8) {
      const mm = parseInt(digits.slice(0, 2), 10);
      const dd = parseInt(digits.slice(2, 4), 10);
      const yyyy = parseInt(digits.slice(4, 8), 10);
      if (mm >= 1 && mm <= 12 && dd >= 1 && dd <= 31) {
        const date = new Date(yyyy, mm - 1, dd);
        return isNaN(date.getTime()) ? undefined : date;
      }
    }
    return undefined;
  }

  function handleInputChange(e: React.ChangeEvent<HTMLInputElement>) {
    const val = e.target.value;
    setInputValue(val);

    if (val.trim() === "") {
      // if cleared, keep it empty
      onChange?.(undefined);
      return;
    }

    const parsed = parseDate(val);
    if (parsed) {
      onChange?.(parsed);
    }
  }

  function handleBlur() {
    if (inputValue.trim() === "") {
      return; // leave it empty
    }

    const parsed = parseDate(inputValue);
    if (parsed) {
      setInputValue(format(parsed, "MM/dd/yyyy"));
    } else if (value) {
      // if invalid, fallback to last valid value
      if (typeof value === "string") {
        setInputValue(value);
      } else {
        setInputValue(format(value, "MM/dd/yyyy"));
      }
    } else {
      // otherwise clear it
      setInputValue("");
    }
  }

  // NEW: Handle input click to open calendar
  const handleInputClick = () => {
    if (!disabled) {
      setOpen(true);
    }
  };

  return (
    <div className={cn("flex w-full items-center relative", className)}>
      <Input
        type="text"
        placeholder={placeholder}
        value={inputValue}
        onChange={handleInputChange}
        onBlur={handleBlur}
        onClick={handleInputClick} // NEW: Click to open calendar
        disabled={disabled}
        className={cn(
          "pr-10 text-sm bg-transparent",
          "focus-visible:ring-0 focus-visible:ring-offset-0",
          "placeholder:text-muted-foreground/60",
          inputClassName
        )}
      />
      <Popover open={open} onOpenChange={setOpen}>
        <PopoverTrigger asChild className="absolute right-0 top-0">
          <Button
            type="button"
            variant="ghost"
            disabled={disabled}
            className={cn(
              "h-full px-3 hover:bg-transparent focus:bg-transparent active:bg-transparent",
              disabled && "opacity-50 cursor-not-allowed"
            )}
          >
            <CalendarDays className="h-auto w-4 opacity-70" />
          </Button>
        </PopoverTrigger>
        <PopoverContent className="w-auto p-0" align="end">
          <Calendar
            mode="single"
            selected={
              parseDate(inputValue) ??
              (typeof value === "string" ? parseDate(value) : value)
            }
            captionLayout="dropdown"
            onSelect={(date) => {
              if (date) {
                onChange?.(date);
                setInputValue(format(date, "MM/dd/yyyy"));
              }
              setOpen(false);
            }}
            className="border-0"
          />
        </PopoverContent>
      </Popover>
    </div>
  );
}

"use client";

import * as React from "react";
import { ChevronsUpDown, Check } from "lucide-react";
import { cn } from "@/lib/utils";
import {
  Popover,
  PopoverTrigger,
  PopoverContent,
} from "@/components/ui/popover";
import {
  Command,
  CommandInput,
  CommandList,
  CommandEmpty,
  CommandGroup,
  CommandItem,
} from "@/components/ui/command";
import { Button } from "@/components/ui/button";
import { FormControl } from "@/components/ui/form";

interface SelectInputProps<T extends Record<string, unknown>> {
  field: {
    value: unknown;
    onChange: (value: unknown) => void;
  };
  data: readonly T[];
  label: string;
  placeholder?: string;
  disabled?: boolean;
  labelKey: keyof T; // which key to display
  valueKey: keyof T; // which key to store
  className?: string;
}

export function SelectInput<T extends Record<string, unknown>>({
  field,
  data,
  label,
  placeholder,
  disabled,
  labelKey,
  valueKey,
  className,
}: SelectInputProps<T>) {
  const [open, setOpen] = React.useState(false);
  const triggerRef = React.useRef<HTMLButtonElement>(null);
  const [popoverWidth, setPopoverWidth] = React.useState<number | undefined>(undefined);

  const selectedItem = data.find((item) => item[valueKey] === field.value);

  // Update popover width when trigger ref is available
  React.useEffect(() => {
    if (triggerRef.current) {
      const width = triggerRef.current.offsetWidth;
      setPopoverWidth(width);
    }
  }, [open]); // Re-calculate when popover opens

  return (
    <FormControl>
      <Popover open={open} onOpenChange={setOpen}>
        <PopoverTrigger asChild>
          <Button
            ref={triggerRef}
            variant="outline"
            role="combobox"
            disabled={disabled}
            className={cn(
              "w-full justify-between border border-input bg-background shadow-sm hover:bg-input hover:text-accent-foreground transition-colors duration-200",
              "text-left font-normal",
              !field.value && "text-muted-foreground",
              disabled && "opacity-50 cursor-not-allowed",
              className
            )}
          >
            <span className="truncate">
              {selectedItem
                ? String(selectedItem[labelKey])
                : placeholder || `Select ${label}`}
            </span>
            <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-60" />
          </Button>
        </PopoverTrigger>
        <PopoverContent
          className="p-0 border border-border shadow-md"
          style={{ width: popoverWidth ? `${popoverWidth}px` : undefined }}
          side="bottom"
          align="start"
          sideOffset={4}
        >
          <Command className="border-0">
            <CommandInput
              placeholder={`Search ${label.toLowerCase()}...`}
              className="h-full border-b border-border"
            />
            <CommandList className="max-h-64">
              <CommandEmpty className="py-6 text-center text-sm text-muted-foreground">
                No {label} found.
              </CommandEmpty>
              <CommandGroup className="p-1">
                {data.map((item) => (
                  <CommandItem
                    key={String(item[valueKey])}
                    value={String(item[labelKey])}
                    onSelect={() => {
                      field.onChange(item[valueKey]);
                      setOpen(false);
                    }}
                    className={cn(
                      "flex items-center justify-between px-3 py-2 text-sm rounded-sm transition-colors duration-150",
                      "aria-selected:bg-accent/20 aria-selected:text-accent-foreground",
                      "hover:bg-accent/20 hover:text-accent-foreground cursor-pointer"
                    )}
                  >
                    <span className="truncate">{String(item[labelKey])}</span>
                    <Check
                      className={cn(
                        "ml-2 h-4 w-4 shrink-0 transition-opacity duration-200",
                        item[valueKey] === field.value
                          ? "opacity-100 text-primary"
                          : "opacity-0"
                      )}
                    />
                  </CommandItem>
                ))}
              </CommandGroup>
            </CommandList>
          </Command>
        </PopoverContent>
      </Popover>
    </FormControl>
  );
}

"use client";

import * as React from "react";
import { Command as CommandPrimitive } from "cmdk";
import { XIcon, ChevronsUpDown } from "lucide-react";

import { cn } from "@/lib/utils";
import {
  Command,
  CommandGroup,
  CommandItem,
  CommandList,
  CommandEmpty,
} from "@/components/ui/command";
import { Button } from "@/components/ui/button";
import { FormControl } from "@/components/ui/form";

export interface Option {
  value: string | number;
  label: string;
  disable?: boolean;
  fixed?: boolean;
  [key: string]: string | number | boolean | undefined;
}

export interface SingleSelectorProps<
  T extends Record<string, unknown> = Record<string, unknown>
> {
  field: {
    value: unknown;
    onChange: (value: unknown) => void;
  };
  data: readonly T[];
  label?: string;
  placeholder?: string;
  disabled?: boolean;
  labelKey: string;
  valueKey: string;
  className?: string;
}

export function SingleSelector<
  T extends Record<string, unknown> = Record<string, unknown>
>({
  field,
  data,
  label,
  placeholder,
  disabled,
  labelKey,
  valueKey,
  className,
}: SingleSelectorProps<T>) {
  const inputRef = React.useRef<HTMLInputElement>(null);
  const dropdownRef = React.useRef<HTMLDivElement>(null);
  const [open, setOpen] = React.useState(false);
  const [inputValue, setInputValue] = React.useState("");

  // Safely index into T with labelKey / valueKey
  const getLabel = React.useCallback(
    (item: T): string => {
      const key = labelKey as keyof T;
      const raw = item[key];
      return raw == null ? "" : String(raw);
    },
    [labelKey]
  );

  const getValue = React.useCallback(
    (item: T): unknown => {
      const key = valueKey as keyof T;
      return item[key];
    },
    [valueKey]
  );

  // Find the selected item
  const selectedItem = React.useMemo(() => {
    const key = valueKey as keyof T;
    return (
      data.find((item) => item[key] === field.value) ?? null
    );
  }, [data, field.value, valueKey]);

  // Update input value when selected item changes
  React.useEffect(() => {
    if (selectedItem) {
      setInputValue(getLabel(selectedItem));
    } else {
      setInputValue("");
    }
  }, [selectedItem, getLabel]);

  const handleClickOutside = (event: MouseEvent | TouchEvent) => {
    if (
      dropdownRef.current &&
      !dropdownRef.current.contains(event.target as Node) &&
      inputRef.current &&
      !inputRef.current.contains(event.target as Node)
    ) {
      setOpen(false);
    }
  };

  React.useEffect(() => {
    if (open) {
      document.addEventListener("mousedown", handleClickOutside);
      document.addEventListener("touchend", handleClickOutside);
    } else {
      document.removeEventListener("mousedown", handleClickOutside);
      document.removeEventListener("touchend", handleClickOutside);
    }

    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
      document.removeEventListener("touchend", handleClickOutside);
    };
  }, [open]);

  const handleUnselect = React.useCallback(() => {
    field.onChange(null);
    setInputValue("");
  }, [field]);

  const handleSelectItem = React.useCallback(
    (item: T) => {
      field.onChange(getValue(item));
      setOpen(false);
    },
    [field, getValue]
  );

  const filteredData = React.useMemo(() => {
    if (!inputValue) return data;

    const lowerInput = inputValue.toLowerCase();
    return data.filter((item) =>
      getLabel(item).toLowerCase().includes(lowerInput)
    );
  }, [data, inputValue, getLabel]);

  return (
    <FormControl>
      <Command
        ref={dropdownRef}
        className={cn("h-auto overflow-visible bg-transparent")}
      >
        <div
          className={cn(
            "relative flex items-center w-full h-full rounded-md border border-input bg-background px-3 text-sm ring-offset-background",
            "placeholder:text-muted-foreground",
            "disabled:cursor-not-allowed disabled:opacity-50 transition-colors duration-200",
            disabled && "cursor-not-allowed opacity-50",
            className
          )}
          onClick={() => {
            if (disabled) return;
            inputRef?.current?.focus();
            setOpen(true);
          }}
        >
          <CommandPrimitive.Input
            ref={inputRef}
            value={inputValue}
            disabled={disabled}
            onValueChange={(value) => {
              setInputValue(value);
            }}
            onBlur={() => {
              // Reset input value to selected item's label when blurring
              if (selectedItem) {
                setInputValue(getLabel(selectedItem));
              }
            }}
            onFocus={() => {
              setOpen(true);
            }}
            placeholder={placeholder || `Select ${label ?? ""}...`}
            className={cn(
              "flex-1 bg-transparent outline-hidden placeholder:text-muted-foreground disabled:cursor-not-allowed border-0 p-0 focus:outline-none focus:ring-0 text-sm"
            )}
          />

          <div className="flex items-center gap-1 ml-2">
            {selectedItem && (
              <Button
                type="button"
                variant="ghost"
                size="sm"
                className="h-4 w-4 p-0 hover:bg-accent text-muted-foreground hover:text-foreground"
                onClick={(e) => {
                  e.stopPropagation();
                  handleUnselect();
                }}
              >
                <XIcon className="h-2.5 w-2.5" />
              </Button>
            )}
            <ChevronsUpDown className="h-3.5 w-3.5 text-muted-foreground shrink-0" />
          </div>
        </div>

        <div className="relative">
          <div
            className={cn(
              "absolute top-1 z-10 w-full overflow-hidden rounded-md border border-input shadow-md bg-popover",
              "data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=closed]:zoom-out-95 data-[state=open]:animate-in data-[state=open]:fade-in-0 data-[state=open]:zoom-in-95",
              !open && "hidden"
            )}
            data-state={open ? "open" : "closed"}
          >
            {open && (
              <CommandList className="outline-hidden max-h-60">
                <CommandEmpty className="py-4 text-center text-sm text-muted-foreground">
                  No results found.
                </CommandEmpty>

                <CommandGroup className="h-full overflow-auto">
                  {filteredData.map((item) => {
                    const isSelected = getValue(item) === field.value;
                    const itemLabel = getLabel(item);

                    return (
                      <CommandItem
                        key={String(getValue(item))}
                        value={itemLabel}
                        onSelect={() => handleSelectItem(item)}
                        className={cn(
                          "cursor-pointer px-2 py-1.5 text-sm transition-colors",
                          "hover:bg-accent hover:text-accent-foreground",
                          isSelected && "bg-primary/10 text-primary font-medium"
                        )}
                      >
                        <span className="flex-1 truncate">
                          {itemLabel}
                        </span>
                        {isSelected && (
                          <div className="ml-2 h-3.5 w-3.5 flex items-center justify-center">
                            <div className="h-2 w-2 rounded-full bg-primary" />
                          </div>
                        )}
                      </CommandItem>
                    );
                  })}
                </CommandGroup>
              </CommandList>
            )}
          </div>
        </div>
      </Command>
    </FormControl>
  );
}

